// AUTO-GENERATED from the bold redesign. Do not edit by hand.
// Markup + styles for the homepage; wired up by ./page.tsx.
export const HOME_STYLES = "html{color-scheme:light;}\nhtml body{background-color:var(--paper);color:var(--ink);font-family:'Bricolage Grotesque',-apple-system,sans-serif;}\n\n  :root{\n    --paper:#ECE6D9;\n    --paper-2:#E3DCCB;\n    --ink:#16130E;\n    --ink-soft:#5c5448;\n    --ink-line:rgba(22,19,14,0.16);\n    --ink-line-strong:rgba(22,19,14,0.42);\n    --acc:#FF3D1F;\n    --acc-ink:#E22E10;\n    --cashew:#2faa55;\n    --walnut:#1f97ad;\n    --ticker:#e07a00;\n    --grid:rgba(22,19,14,0.045);\n    --ease:cubic-bezier(.22,.61,.36,1);\n    --maxw:1280px;\n  }\n  *{box-sizing:border-box;margin:0;padding:0;}\n  html{-webkit-text-size-adjust:100%;scroll-behavior:smooth;}\n  body{\n    font-family:'Bricolage Grotesque',-apple-system,sans-serif;\n    background:var(--paper);\n    color:var(--ink);\n    line-height:1.5;\n    -webkit-font-smoothing:antialiased;\n    -moz-osx-font-smoothing:grayscale;\n    overflow-x:hidden;\n    background-image:\n      linear-gradient(var(--grid) 1px, transparent 1px),\n      linear-gradient(90deg, var(--grid) 1px, transparent 1px);\n    background-size:46px 46px;\n  }\n  a{color:inherit;text-decoration:none;}\n  img{display:block;max-width:100%;}\n  .mono{font-family:'JetBrains Mono',monospace;}\n  .wrap{max-width:var(--maxw);margin:0 auto;padding:0 32px;}\n  .acc{color:var(--acc);}\n  section{position:relative;}\n  ::selection{background:var(--acc);color:var(--paper);}\n\n  /* ---------- Top bar ---------- */\n  .bar{position:fixed;top:0;left:0;right:0;z-index:100;height:46px;\n    background:rgba(236,230,217,0.82);backdrop-filter:blur(8px);-webkit-backdrop-filter:blur(8px);\n    border-bottom:1px solid var(--ink);}\n  .bar .wrap{height:100%;display:flex;align-items:center;justify-content:space-between;gap:20px;}\n  .bar-brand{font-family:'JetBrains Mono',monospace;font-weight:700;font-size:13px;letter-spacing:0.02em;display:flex;align-items:center;gap:8px;}\n  .bar-brand .sq{display:inline-flex;width:18px;height:18px;background:var(--acc);color:var(--paper);align-items:center;justify-content:center;font-size:12px;font-weight:700;}\n  .bar-nav{display:flex;gap:26px;font-family:'JetBrains Mono',monospace;font-size:12px;font-weight:500;letter-spacing:0.04em;}\n  .bar-nav a{color:var(--ink-soft);transition:color .18s;position:relative;}\n  .bar-nav a:hover{color:var(--ink);}\n  .bar-nav a::after{content:\"\";position:absolute;left:0;bottom:-3px;width:0;height:1.5px;background:var(--acc);transition:width .25s var(--ease);}\n  .bar-nav a:hover::after{width:100%;}\n  .bar-clock{font-family:'JetBrains Mono',monospace;font-size:12px;font-weight:500;color:var(--ink-soft);letter-spacing:0.02em;white-space:nowrap;}\n  .bar-clock b{color:var(--acc);font-weight:600;}\n  .bar-menu{display:none;background:none;border:1px solid var(--ink);width:34px;height:28px;cursor:pointer;flex-direction:column;align-items:center;justify-content:center;gap:4px;}\n  .bar-menu span{width:16px;height:1.6px;background:var(--ink);transition:.3s var(--ease);}\n  .bar-menu.open span:nth-child(1){transform:translateY(5.6px) rotate(45deg);}\n  .bar-menu.open span:nth-child(2){opacity:0;}\n  .bar-menu.open span:nth-child(3){transform:translateY(-5.6px) rotate(-45deg);}\n  .m-menu{position:fixed;top:46px;left:0;right:0;z-index:99;background:var(--ink);color:var(--paper);\n    border-bottom:1px solid var(--ink);transform:translateY(-120%);transition:transform .4s var(--ease);\n    font-family:'JetBrains Mono',monospace;}\n  .m-menu.open{transform:translateY(0);}\n  .m-menu a{display:block;padding:16px 32px;border-bottom:1px solid rgba(236,230,217,0.14);font-size:14px;letter-spacing:0.04em;}\n  .m-menu a:last-child{border-bottom:none;}\n\n  /* ---------- Hero ---------- */\n  .hero{padding:120px 0 0;border-bottom:1px solid var(--ink);}\n  .hero .wrap{display:grid;grid-template-columns:1fr;gap:0;}\n  .hero-tag{font-family:'JetBrains Mono',monospace;font-size:13px;font-weight:500;letter-spacing:0.06em;\n    color:var(--ink-soft);display:flex;align-items:center;gap:12px;margin-bottom:30px;}\n  .hero-tag::before{content:\"\";width:42px;height:1px;background:var(--acc);}\n  .hero-name{font-weight:800;line-height:0.84;letter-spacing:-0.045em;\n    font-size:clamp(4rem,16.5vw,15rem);text-transform:uppercase;}\n  .hero-name .l2{display:block;}\n  .hero-name .dot{color:var(--acc);}\n  .hero-lower{display:grid;grid-template-columns:1.35fr 1fr;gap:44px;align-items:end;\n    margin-top:38px;padding-bottom:46px;}\n  .hero-state{font-size:clamp(1.25rem,2.6vw,2rem);font-weight:500;line-height:1.18;letter-spacing:-0.02em;max-width:18ch;}\n  .hero-state b{font-weight:700;}\n  .hero-cta{display:flex;gap:10px;margin-top:30px;flex-wrap:wrap;}\n  .lnk{font-family:'JetBrains Mono',monospace;font-size:13px;font-weight:600;letter-spacing:0.03em;\n    border:1px solid var(--ink);padding:13px 20px;display:inline-flex;align-items:center;gap:10px;\n    transition:.22s var(--ease);text-transform:uppercase;}\n  .lnk:hover{background:var(--ink);color:var(--paper);transform:translate(-2px,-2px);box-shadow:4px 4px 0 var(--acc);}\n  .lnk.fill{background:var(--acc);color:var(--paper);border-color:var(--acc);}\n  .lnk.fill:hover{background:var(--ink);border-color:var(--ink);box-shadow:4px 4px 0 var(--acc);}\n  /* spec sheet */\n  .spec{font-family:'JetBrains Mono',monospace;font-size:13px;border-top:1px solid var(--ink);}\n  .spec-row{display:grid;grid-template-columns:96px 1fr;gap:14px;padding:11px 0;border-bottom:1px solid var(--ink-line);}\n  .spec-row .k{color:var(--ink-soft);letter-spacing:0.04em;}\n  .spec-row .v{color:var(--ink);font-weight:500;}\n\n  /* ---------- Marquee ---------- */\n  .marquee{background:var(--ink);color:var(--paper);overflow:hidden;border-bottom:1px solid var(--ink);padding:14px 0;}\n  .mq-track{display:inline-flex;white-space:nowrap;will-change:transform;animation:scroll 34s linear infinite;}\n  .mq-track span{font-family:'JetBrains Mono',monospace;font-size:14px;font-weight:500;letter-spacing:0.06em;\n    padding:0 22px;display:inline-flex;align-items:center;gap:22px;text-transform:uppercase;}\n  .mq-track span::after{content:\"✦\";color:var(--acc);}\n  @keyframes scroll{from{transform:translateX(0);}to{transform:translateX(-50%);}}\n  .marquee:hover .mq-track{animation-play-state:paused;}\n\n  /* ---------- Section scaffold ---------- */\n  .sec{padding:clamp(72px,9vw,128px) 0;border-bottom:1px solid var(--ink);}\n  .sec-num{font-family:'JetBrains Mono',monospace;font-size:13px;font-weight:600;letter-spacing:0.1em;\n    color:var(--acc);margin-bottom:18px;display:flex;align-items:center;gap:12px;}\n  .sec-num::after{content:\"\";flex:1;height:1px;background:var(--ink-line);}\n  .sec-title{font-weight:800;font-size:clamp(2.2rem,5.4vw,4.4rem);line-height:0.96;letter-spacing:-0.035em;\n    text-transform:uppercase;}\n\n  /* ---------- Metrics (dark) ---------- */\n  .metrics{background:var(--ink);color:var(--paper);border-bottom:1px solid var(--ink);\n    background-image:linear-gradient(rgba(236,230,217,0.04) 1px,transparent 1px),linear-gradient(90deg,rgba(236,230,217,0.04) 1px,transparent 1px);background-size:46px 46px;}\n  .metrics .sec-num{color:var(--acc);}\n  .metrics .sec-num::after{background:rgba(236,230,217,0.18);}\n  .metrics-grid{display:grid;grid-template-columns:repeat(4,1fr);margin-top:48px;border-top:1px solid rgba(236,230,217,0.22);}\n  .metric{padding:34px 26px 30px;border-right:1px solid rgba(236,230,217,0.18);position:relative;}\n  .metric:last-child{border-right:none;}\n  .metric .n{font-weight:800;font-size:clamp(2.8rem,5.6vw,5.2rem);line-height:0.9;letter-spacing:-0.04em;}\n  .metric:nth-child(1) .n .u,.metric .n .u{color:var(--acc);}\n  .metric .l{font-family:'JetBrains Mono',monospace;font-size:12px;letter-spacing:0.08em;text-transform:uppercase;\n    color:rgba(236,230,217,0.66);margin-top:16px;}\n  .metric .idx{position:absolute;top:14px;right:16px;font-family:'JetBrains Mono',monospace;font-size:11px;color:rgba(236,230,217,0.4);}\n\n  /* ---------- About ---------- */\n  .about-grid{display:grid;grid-template-columns:0.42fr 1fr;gap:56px;margin-top:30px;}\n  .about-lead{font-size:clamp(1.5rem,3vw,2.5rem);font-weight:500;line-height:1.22;letter-spacing:-0.02em;}\n  .about-lead b{font-weight:700;}\n  .about-body{font-size:1.05rem;color:var(--ink-soft);line-height:1.65;margin-top:24px;max-width:54ch;font-weight:500;}\n  .about-side{font-family:'JetBrains Mono',monospace;font-size:12.5px;color:var(--ink-soft);line-height:1.9;border-top:2px solid var(--ink);padding-top:18px;}\n  .about-side b{color:var(--ink);display:block;font-weight:700;letter-spacing:0.04em;margin-bottom:10px;}\n\n  /* ---------- Work index ---------- */\n  .idx-head{display:grid;grid-template-columns:64px 1fr 60px;gap:24px;\n    font-family:'JetBrains Mono',monospace;font-size:11.5px;letter-spacing:0.1em;text-transform:uppercase;\n    color:var(--ink-soft);padding:0 0 14px;border-bottom:2px solid var(--ink);margin-top:42px;}\n  .app{display:block;border-bottom:1px solid var(--ink);position:relative;transition:background .35s var(--ease),color .35s var(--ease);}\n  .app:hover{background:var(--ink);color:var(--paper);}\n  .app-inner{display:grid;grid-template-columns:64px 1fr 60px;gap:24px;align-items:center;padding:26px 16px 26px 0;transition:padding .3s var(--ease);}\n  .app:hover .app-inner{padding-left:18px;}\n  .app-icon{width:60px;height:60px;border-radius:13px;border:1px solid var(--ink-line);overflow:hidden;background:var(--paper-2);transition:border-color .35s;}\n  .app:hover .app-icon{border-color:rgba(236,230,217,0.3);}\n  .app-icon img{width:100%;height:100%;object-fit:cover;}\n  .app-icon.mono{display:flex;align-items:center;justify-content:center;font-weight:800;font-size:26px;color:#fff;}\n  .app-main .nm{font-weight:800;font-size:clamp(1.7rem,3.4vw,2.7rem);line-height:1;letter-spacing:-0.03em;display:flex;align-items:baseline;gap:14px;flex-wrap:wrap;}\n  .app-main .cat{font-family:'JetBrains Mono',monospace;font-size:12px;letter-spacing:0.04em;text-transform:uppercase;color:var(--acc);font-weight:600;}\n  .app:hover .app-main .cat{color:var(--acc);}\n  .app-main .ds{font-size:14.5px;color:var(--ink-soft);line-height:1.55;margin-top:10px;max-width:60ch;font-weight:500;transition:color .35s;}\n  .app:hover .app-main .ds{color:rgba(236,230,217,0.7);}\n  .app-stack{display:flex;flex-wrap:wrap;gap:6px;}\n  .app-stack span{font-family:'JetBrains Mono',monospace;font-size:11px;letter-spacing:0.02em;color:var(--ink-soft);border:1px solid var(--ink-line);padding:4px 8px;transition:.35s;}\n  .app:hover .app-stack span{color:rgba(236,230,217,0.8);border-color:rgba(236,230,217,0.28);}\n  .app-arrow{justify-self:end;font-size:30px;line-height:1;transition:transform .3s var(--ease),color .3s;color:var(--ink);}\n  .app:hover .app-arrow{transform:translate(5px,-5px);color:var(--acc);}\n  .app .tick{position:absolute;left:0;top:0;bottom:0;width:4px;background:var(--acc);transform:scaleY(0);transform-origin:top;transition:transform .35s var(--ease);}\n  .app:hover .tick{transform:scaleY(1);}\n\n  /* ---------- Flagship (Popup) ---------- */\n  .flag-head{display:flex;align-items:flex-end;justify-content:space-between;gap:24px;flex-wrap:wrap;margin-top:8px;}\n  .flag-title{display:flex;align-items:baseline;gap:18px;flex-wrap:wrap;}\n  .flag-title h2{font-weight:800;font-size:clamp(3rem,8vw,6.5rem);line-height:0.9;letter-spacing:-0.04em;}\n  .flag-title h2 .dot{color:var(--acc);}\n  .flag-role{font-family:'JetBrains Mono',monospace;font-size:12.5px;letter-spacing:0.06em;text-transform:uppercase;color:var(--ink-soft);}\n  .flag-visit{font-family:'JetBrains Mono',monospace;font-size:13px;font-weight:600;letter-spacing:0.04em;text-transform:uppercase;\n    border:1px solid var(--ink);padding:12px 18px;display:inline-flex;align-items:center;gap:10px;transition:.22s var(--ease);white-space:nowrap;}\n  .flag-visit:hover{background:var(--acc);color:var(--paper);border-color:var(--acc);transform:translate(-2px,-2px);box-shadow:4px 4px 0 var(--ink);}\n  .flag-lead{font-size:clamp(1.15rem,2vw,1.6rem);font-weight:500;line-height:1.4;letter-spacing:-0.015em;max-width:64ch;margin-top:30px;}\n  .flag-lead b{font-weight:700;}\n  .surfaces{display:grid;grid-template-columns:repeat(3,1fr);gap:0;margin-top:44px;border:1px solid var(--ink);}\n  .surface{padding:26px 24px;border-right:1px solid var(--ink);}\n  .surface:last-child{border-right:none;}\n  .surface .sx{font-family:'JetBrains Mono',monospace;font-size:11.5px;letter-spacing:0.1em;color:var(--acc);font-weight:600;margin-bottom:14px;}\n  .surface h4{font-weight:800;font-size:1.18rem;letter-spacing:-0.02em;margin-bottom:8px;}\n  .surface p{font-size:14px;color:var(--ink-soft);line-height:1.55;font-weight:500;}\n  .surface .st{font-family:'JetBrains Mono',monospace;font-size:11px;color:var(--ink-soft);letter-spacing:0.02em;margin-top:14px;line-height:1.7;}\n  .flag-stats{display:grid;grid-template-columns:repeat(4,1fr);border:1px solid var(--ink);border-top:none;}\n  .flag-stat{padding:24px 22px;border-right:1px solid var(--ink);}\n  .flag-stat:last-child{border-right:none;}\n  .flag-stat .n{font-weight:800;font-size:clamp(1.8rem,3.6vw,2.9rem);line-height:0.9;letter-spacing:-0.035em;}\n  .flag-stat .n .u{color:var(--acc);}\n  .flag-stat .l{font-family:'JetBrains Mono',monospace;font-size:10.5px;letter-spacing:0.07em;text-transform:uppercase;color:var(--ink-soft);margin-top:11px;}\n  .caps{display:grid;grid-template-columns:repeat(4,1fr);gap:26px;margin-top:48px;}\n  .cap h5{font-family:'JetBrains Mono',monospace;font-size:11.5px;letter-spacing:0.08em;text-transform:uppercase;color:var(--ink-soft);\n    padding-bottom:11px;border-bottom:1px solid var(--ink);margin-bottom:13px;}\n  .cap ul{list-style:none;display:flex;flex-direction:column;gap:8px;}\n  .cap li{font-size:13.5px;font-weight:500;line-height:1.4;display:flex;gap:8px;}\n  .cap li::before{content:\"▸\";color:var(--acc);flex-shrink:0;font-size:11px;line-height:1.5;}\n  .flag-tech{font-family:'JetBrains Mono',monospace;font-size:12px;color:var(--ink-soft);line-height:1.9;\n    margin-top:40px;border-top:2px solid var(--ink);padding-top:20px;}\n  .flag-tech div{display:flex;gap:14px;padding:3px 0;flex-wrap:wrap;}\n  .flag-tech .k{color:var(--acc);font-weight:600;min-width:130px;letter-spacing:0.04em;}\n  .flag-tech .v{color:var(--ink);flex:1;min-width:240px;}\n\n  /* ---------- Experience ledger ---------- */\n  .led{margin-top:30px;border-top:2px solid var(--ink);}\n  .led-item{display:grid;grid-template-columns:150px 1fr;gap:40px;padding:36px 0;border-bottom:1px solid var(--ink);}\n  .led-when{font-family:'JetBrains Mono',monospace;font-size:13px;font-weight:500;color:var(--ink-soft);}\n  .led-when .yr{font-size:26px;font-weight:700;color:var(--ink);display:block;letter-spacing:-0.02em;margin-bottom:6px;}\n  .led-when .loc{display:block;margin-top:10px;font-size:11.5px;letter-spacing:0.04em;text-transform:uppercase;}\n  .led-co{display:flex;align-items:center;gap:14px;margin-bottom:6px;flex-wrap:wrap;}\n  .led-co h3{font-weight:800;font-size:clamp(1.5rem,3vw,2.2rem);letter-spacing:-0.025em;line-height:1;}\n  .led-co .role{font-family:'JetBrains Mono',monospace;font-size:12.5px;color:var(--ink-soft);letter-spacing:0.03em;}\n  .led-metrics{display:flex;flex-wrap:wrap;gap:8px;margin:14px 0 14px;}\n  .led-metrics span{font-family:'JetBrains Mono',monospace;font-size:12px;font-weight:600;letter-spacing:0.02em;\n    color:var(--acc-ink);border:1px solid var(--acc);padding:5px 11px;display:inline-flex;align-items:center;gap:7px;}\n  .led-metrics span::before{content:\"▸\";}\n  .led-desc{font-size:1.02rem;color:var(--ink);line-height:1.6;max-width:62ch;font-weight:500;}\n  .led-skills{display:flex;flex-wrap:wrap;gap:6px;margin-top:16px;}\n  .led-skills span{font-family:'JetBrains Mono',monospace;font-size:11px;color:var(--ink-soft);letter-spacing:0.02em;}\n  .led-skills span:not(:last-child)::after{content:\" /\";color:var(--ink-line-strong);}\n\n  /* ---------- Skills ---------- */\n  .skills-mq{border-top:2px solid var(--ink);border-bottom:1px solid var(--ink);overflow:hidden;padding:22px 0;margin-top:30px;}\n  .skills-mq .mq-track{animation-duration:40s;}\n  .skills-mq .mq-track.rev{animation-direction:reverse;animation-duration:46s;}\n  .skills-mq span{font-weight:800;font-size:clamp(1.6rem,3.4vw,2.6rem);letter-spacing:-0.02em;text-transform:uppercase;\n    color:var(--ink);font-family:'Bricolage Grotesque',sans-serif;padding:0 18px;gap:18px;}\n  .skills-mq span::after{content:\"·\";color:var(--acc);}\n  .skills-mq .row2{margin-top:10px;}\n  .skills-mq .row2 span{color:transparent;-webkit-text-stroke:1px var(--ink-line-strong);}\n  .skills-cols{display:grid;grid-template-columns:repeat(4,1fr);gap:24px;margin-top:46px;}\n  .skill-col h4{font-family:'JetBrains Mono',monospace;font-size:12px;letter-spacing:0.08em;text-transform:uppercase;\n    color:var(--ink-soft);padding-bottom:12px;border-bottom:1px solid var(--ink);margin-bottom:14px;}\n  .skill-col ul{list-style:none;display:flex;flex-direction:column;gap:9px;}\n  .skill-col li{font-size:15px;font-weight:600;letter-spacing:-0.01em;display:flex;align-items:center;gap:9px;}\n  .skill-col li::before{content:\"→\";color:var(--acc);font-family:'JetBrains Mono',monospace;font-size:13px;}\n\n  /* ---------- Contact ---------- */\n  .contact{background:var(--ink);color:var(--paper);border-bottom:1px solid var(--ink);\n    background-image:linear-gradient(rgba(236,230,217,0.04) 1px,transparent 1px),linear-gradient(90deg,rgba(236,230,217,0.04) 1px,transparent 1px);background-size:46px 46px;}\n  .contact .sec-num{color:var(--acc);}\n  .contact .sec-num::after{background:rgba(236,230,217,0.18);}\n  .contact h2{font-weight:800;font-size:clamp(2.8rem,9vw,8rem);line-height:0.86;letter-spacing:-0.04em;\n    text-transform:uppercase;margin:18px 0 40px;}\n  .mail{display:inline-flex;align-items:center;gap:18px;font-weight:700;font-size:clamp(1.3rem,3.6vw,2.6rem);\n    letter-spacing:-0.02em;border-bottom:2px solid rgba(236,230,217,0.3);padding-bottom:8px;transition:.25s var(--ease);}\n  .mail:hover{color:var(--acc);border-color:var(--acc);gap:26px;}\n  .socials{display:flex;gap:0;margin-top:64px;border-top:1px solid rgba(236,230,217,0.22);\n    font-family:'JetBrains Mono',monospace;flex-wrap:wrap;}\n  .socials a{flex:1;min-width:160px;padding:22px 4px;border-right:1px solid rgba(236,230,217,0.18);\n    font-size:13px;letter-spacing:0.06em;text-transform:uppercase;display:flex;align-items:center;justify-content:space-between;\n    color:rgba(236,230,217,0.78);transition:.22s var(--ease);}\n  .socials a:last-child{border-right:none;}\n  .socials a:hover{color:var(--paper);padding-left:14px;}\n  .socials a span.ar{color:var(--acc);}\n\n  /* ---------- Footer / colophon ---------- */\n  footer{background:var(--ink);color:rgba(236,230,217,0.6);padding:30px 0;font-family:'JetBrains Mono',monospace;}\n  footer .wrap{display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:12px;font-size:12px;letter-spacing:0.03em;}\n  footer .col{color:rgba(236,230,217,0.45);}\n  footer a:hover{color:var(--acc);}\n\n  /* ---------- Reveal ---------- */\n  [data-reveal]{opacity:0;transform:translateY(26px);transition:opacity .7s var(--ease),transform .7s var(--ease);transition-delay:var(--d,0s);}\n  [data-reveal].in{opacity:1;transform:none;}\n\n  /* ---------- Responsive ---------- */\n  @media (max-width:1040px){\n    .bar-clock{display:none;}\n    .surfaces{grid-template-columns:1fr;}\n    .surface{border-right:none;border-bottom:1px solid var(--ink);}\n    .surface:last-child{border-bottom:none;}\n    .flag-stats{grid-template-columns:repeat(2,1fr);}\n    .flag-stat:nth-child(2){border-right:none;}\n    .flag-stat:nth-child(1),.flag-stat:nth-child(2){border-bottom:1px solid var(--ink);}\n    .caps{grid-template-columns:repeat(2,1fr);gap:30px 26px;}\n  }\n  @media (max-width:1000px){\n    .hero-lower{grid-template-columns:1fr;gap:34px;}\n    .metrics-grid{grid-template-columns:repeat(2,1fr);}\n    .metric:nth-child(2){border-right:none;}\n    .metric:nth-child(1),.metric:nth-child(2){border-bottom:1px solid rgba(236,230,217,0.18);}\n    .about-grid{grid-template-columns:1fr;gap:34px;}\n    .skills-cols{grid-template-columns:repeat(2,1fr);gap:30px 24px;}\n    .idx-head{grid-template-columns:52px 1fr 50px;}\n    .idx-head .h-stack{display:none;}\n    .app-inner{grid-template-columns:52px 1fr 50px;gap:18px;align-items:start;}\n    .app-stack{margin-top:12px;}\n  }\n  @media (max-width:680px){\n    .wrap{padding:0 20px;}\n    .bar-nav{display:none;}\n    .bar-clock{display:none;}\n    .bar-menu{display:flex;}\n    .hero{padding:96px 0 0;}\n    .led-item{grid-template-columns:1fr;gap:14px;}\n    .led-when{display:flex;align-items:baseline;gap:14px;}\n    .led-when .yr{margin-bottom:0;}\n    .led-when .loc{margin-top:0;}\n    .app-main .nm{font-size:1.7rem;}\n    .app-arrow{display:none;}\n    .skills-cols{grid-template-columns:1fr 1fr;}\n    .socials a{min-width:50%;}\n    .caps{grid-template-columns:1fr;}\n    .flag-head{align-items:flex-start;}\n    .flag-tech .k{min-width:0;width:100%;}\n    .flag-tech .v{min-width:0;}\n  }\n  @media (max-width:430px){\n    .metrics-grid{grid-template-columns:1fr;}\n    .metric{border-right:none;border-bottom:1px solid rgba(236,230,217,0.18);}\n    .skills-cols{grid-template-columns:1fr;}\n    .flag-stats{grid-template-columns:1fr;}\n    .flag-stat{border-right:none;border-bottom:1px solid var(--ink);}\n    .flag-stat:last-child{border-bottom:none;}\n  }\n  @media (prefers-reduced-motion:reduce){\n    *{animation:none !important;}\n    .mq-track{transform:none !important;}\n    [data-reveal]{opacity:1;transform:none;transition:none;}\n    html{scroll-behavior:auto;}\n  }\n";

export const HOME_BODY = "<!-- TOP BAR -->\n<div class=\"bar\">\n  <div class=\"wrap\">\n    <a class=\"bar-brand\" href=\"#top\"><span class=\"sq\">M</span> MAYANK_GANDHI</a>\n    <nav class=\"bar-nav\">\n      <a href=\"#profile\">PROFILE</a>\n      <a href=\"#popup\">POPUP</a>\n      <a href=\"#work\">APPS</a>\n      <a href=\"#experience\">EXPERIENCE</a>\n      <a href=\"#stack\">STACK</a>\n      <a href=\"#contact\">CONTACT</a>\n    </nav>\n    <div class=\"bar-clock\">HYD <b id=\"clock\">--:--:--</b> IST</div>\n    <button class=\"bar-menu\" id=\"menuBtn\" aria-label=\"Menu\"><span></span><span></span><span></span></button>\n  </div>\n</div>\n<nav class=\"m-menu\" id=\"mMenu\">\n  <a href=\"#profile\">01 / PROFILE</a>\n  <a href=\"#popup\">02 / POPUP</a>\n  <a href=\"#work\">03 / APPS</a>\n  <a href=\"#experience\">04 / EXPERIENCE</a>\n  <a href=\"#stack\">05 / STACK</a>\n  <a href=\"#contact\">06 / CONTACT</a>\n</nav>\n\n<!-- HERO -->\n<header class=\"hero\" id=\"top\">\n  <div class=\"wrap\">\n    <div class=\"hero-tag\" data-reveal>iOS ENGINEER &nbsp;·&nbsp; FOUNDER &nbsp;·&nbsp; INDIE MAKER</div>\n    <h1 class=\"hero-name\" data-reveal style=\"--d:.05s\">Mayank<span class=\"l2\">Gandhi<span class=\"dot\">.</span></span></h1>\n    <div class=\"hero-lower\">\n      <div data-reveal style=\"--d:.12s\">\n        <div class=\"hero-state\">I build <b>exceptional software</b> — from native iOS apps to a full commerce platform — with scalable architecture and <span class=\"acc\">performance at the core.</span></div>\n        <div class=\"hero-cta\">\n          <a class=\"lnk fill\" href=\"#work\">↓ View the work</a>\n          <a class=\"lnk\" href=\"mailto:mayankgandhi50@gmail.com\">↗ Email me</a>\n        </div>\n      </div>\n      <div class=\"spec mono\" data-reveal style=\"--d:.18s\">\n        <div class=\"spec-row\"><span class=\"k\">ROLE</span><span class=\"v\">Senior iOS Engineer</span></div>\n        <div class=\"spec-row\"><span class=\"k\">BASED</span><span class=\"v\">Hyderabad, India</span></div>\n        <div class=\"spec-row\"><span class=\"k\">FOCUS</span><span class=\"v\">Architecture · Performance · Leadership</span></div>\n        <div class=\"spec-row\"><span class=\"k\">FLAGSHIP</span><span class=\"v\">Popup — commerce platform</span></div>\n        <div class=\"spec-row\"><span class=\"k\">SHIPPED</span><span class=\"v\">3 iOS apps · 10M+ users reached</span></div>\n        <div class=\"spec-row\"><span class=\"k\">STACK</span><span class=\"v\">Swift · SwiftUI · TCA · Tuist</span></div>\n      </div>\n    </div>\n  </div>\n</header>\n\n<!-- MARQUEE -->\n<div class=\"marquee\" aria-hidden=\"true\">\n  <div class=\"mq-track\">\n    <span>POPUP — COMMERCE PLATFORM</span><span>CASHEW</span><span>WALNUT</span><span>TICKER</span><span>SWIFT &amp; SWIFTUI</span>\n    <span>POPUP — COMMERCE PLATFORM</span><span>CASHEW</span><span>WALNUT</span><span>TICKER</span><span>SWIFT &amp; SWIFTUI</span>\n  </div>\n</div>\n\n<!-- METRICS -->\n<section class=\"metrics\" id=\"metrics\">\n  <div class=\"wrap\" style=\"padding-top:clamp(64px,8vw,104px);padding-bottom:clamp(64px,8vw,104px);\">\n    <div class=\"sec-num\" data-reveal>00 / BY THE NUMBERS</div>\n    <div class=\"sec-title\" data-reveal style=\"color:var(--paper)\">Impact, measured.</div>\n    <div class=\"metrics-grid\">\n      <div class=\"metric\" data-reveal><span class=\"idx\">/01</span><div class=\"n\">10M<span class=\"u\">+</span></div><div class=\"l\">Users reached</div></div>\n      <div class=\"metric\" data-reveal style=\"--d:.07s\"><span class=\"idx\">/02</span><div class=\"n\">$100M<span class=\"u\">+</span></div><div class=\"l\">Revenue impact</div></div>\n      <div class=\"metric\" data-reveal style=\"--d:.14s\"><span class=\"idx\">/03</span><div class=\"n\">$200K</div><div class=\"l\">Cost savings</div></div>\n      <div class=\"metric\" data-reveal style=\"--d:.21s\"><span class=\"idx\">/04</span><div class=\"n\">03</div><div class=\"l\">Apps shipped solo</div></div>\n    </div>\n  </div>\n</section>\n\n<!-- PROFILE -->\n<section class=\"sec\" id=\"profile\">\n  <div class=\"wrap\">\n    <div class=\"sec-num\" data-reveal>01 / PROFILE</div>\n    <div class=\"about-grid\">\n      <div class=\"about-side mono\" data-reveal>\n        <b>// SUMMARY</b>\n        6+ years building<br/>for Apple platforms.<br/><br/>\n        Scale at Grab,<br/>Compass &amp; Radius.<br/><br/>\n        3 apps shipped<br/>independently.<br/><br/>\n        <span class=\"acc\">Based in Hyderabad.</span>\n      </div>\n      <div data-reveal style=\"--d:.1s\">\n        <p class=\"about-lead\">I'm a Senior iOS Engineer who cares about <b>scalable architecture</b>, performance users can feel, and leaving codebases &mdash; and teams &mdash; <span class=\"acc\">better than I found them.</span></p>\n        <p class=\"about-body\">From risk-management systems at Grab that reached 10M+ users, to a Swift modernisation effort across a 35-engineer team at Compass, to architecting a multi-app ecosystem at Radius — I've worked at scale. Alongside that, I design and ship my own apps end to end, from first commit to App Store.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- FLAGSHIP: POPUP -->\n<section class=\"sec\" id=\"popup\">\n  <div class=\"wrap\">\n    <div class=\"sec-num\" data-reveal>02 / FLAGSHIP</div>\n    <div class=\"flag-head\" data-reveal>\n      <div class=\"flag-title\">\n        <h2>Popup<span class=\"dot\">.</span></h2>\n        <span class=\"flag-role\">Founder &amp; Solo Engineer</span>\n      </div>\n      <a class=\"flag-visit\" href=\"https://mypopup.shop\" target=\"_blank\" rel=\"noopener noreferrer\">mypopup.shop ↗</a>\n    </div>\n    <p class=\"flag-lead\" data-reveal style=\"--d:.06s\">A commerce platform for independent retailers and pop-up shops — collapsing POS, online storefront, and back-office into <b>one system with a shared source of truth.</b></p>\n\n    <div class=\"surfaces\" data-reveal style=\"--d:.1s\">\n      <div class=\"surface\">\n        <div class=\"sx\">A / WEB</div>\n        <h4>Dashboard + Storefront</h4>\n        <div class=\"st\">Next.js 15 · React · TypeScript<br/>Tailwind · Radix · TanStack</div>\n      </div>\n      <div class=\"surface\">\n        <div class=\"sx\">B / iOS</div>\n        <h4>Native Seller App</h4>\n        <div class=\"st\">Swift 6 · SwiftUI · Tuist<br/>Factory (DI) · supabase-swift</div>\n      </div>\n      <div class=\"surface\">\n        <div class=\"sx\">C / BACKEND</div>\n        <h4>Single Source of Truth</h4>\n        <div class=\"st\">PostgreSQL (RLS) · Deno Edge<br/>Functions · pgTAP test suite</div>\n      </div>\n    </div>\n\n    <div class=\"flag-stats\" data-reveal style=\"--d:.14s\">\n      <div class=\"flag-stat\"><div class=\"n\">03</div><div class=\"l\">Surfaces, one backend</div></div>\n      <div class=\"flag-stat\"><div class=\"n\">~250</div><div class=\"l\">SQL migrations</div></div>\n      <div class=\"flag-stat\"><div class=\"n\">~60</div><div class=\"l\">Deno edge functions</div></div>\n      <div class=\"flag-stat\"><div class=\"n\">1,800<span class=\"u\">+</span></div><div class=\"l\">pgTAP tests gating CI</div></div>\n    </div>\n\n    <div class=\"flag-tech mono\" data-reveal style=\"--d:.16s\">\n      <div><span class=\"k\">HANDLES</span><span class=\"v\">Browser POS · Razorpay/UPI · settlement reconciliation · GST invoicing · inventory &amp; purchases · subscription billing · email + SMS · reviews · CSV import · PostHog</span></div>\n    </div>\n  </div>\n</section>\n\n<!-- WORK INDEX -->\n<section class=\"sec\" id=\"work\">\n  <div class=\"wrap\">\n    <div class=\"sec-num\" data-reveal>03 / SELECTED WORK</div>\n    <div class=\"sec-title\" data-reveal>Apps, shipped<br/>solo.</div>\n    <div class=\"idx-head\" data-reveal><span>—</span><span>APP / CATEGORY</span><span style=\"text-align:right\">↗</span></div>\n\n    <a class=\"app\" href=\"https://mayankgandhi.com/cashew\" data-reveal>\n      <span class=\"tick\"></span>\n      <div class=\"app-inner\">\n        <div class=\"app-icon\"><img src=\"https://cdn.mayankgandhi.com/cashew-app-icon.png\" alt=\"Cashew app icon\" /></div>\n        <div class=\"app-main\">\n          <div class=\"nm\">Cashew <span class=\"cat\">Credit Card Tracker</span></div>\n          <div class=\"ds\">Published financial-management app for bill tracking and payment oversight. Modular Tuist architecture, Core Data persistence, push alerts, home-screen widgets, and Combine for reactive data binding.</div>\n          <div class=\"app-stack\" style=\"margin-top:14px;\"><span>Tuist</span><span>Core Data</span><span>Combine</span><span>WidgetKit</span></div>\n        </div>\n        <div class=\"app-arrow\">↗</div>\n      </div>\n    </a>\n\n    <a class=\"app\" href=\"https://mayankgandhi.com/walnut\" data-reveal>\n      <span class=\"tick\"></span>\n      <div class=\"app-inner\">\n        <div class=\"app-icon\"><img src=\"https://cdn.mayankgandhi.com/walnut-app-icon.png\" alt=\"Walnut app icon\" /></div>\n        <div class=\"app-main\">\n          <div class=\"nm\">Walnut <span class=\"cat\">Medical Documents Manager</span></div>\n          <div class=\"ds\">Personal wellness app for medication adherence and prescription management. Automatic prescription parsing, medication reminders, follow-up scheduling, and real-time health metrics — built with SwiftUI &amp; SwiftData.</div>\n          <div class=\"app-stack\" style=\"margin-top:14px;\"><span>SwiftUI</span><span>SwiftData</span><span>Notifications</span><span>Parsing</span></div>\n        </div>\n        <div class=\"app-arrow\">↗</div>\n      </div>\n    </a>\n\n    <a class=\"app\" href=\"https://mayankgandhi.com/ticker\" data-reveal>\n      <span class=\"tick\"></span>\n      <div class=\"app-inner\">\n        <div class=\"app-icon\"><img src=\"https://cdn.mayankgandhi.com/ticker-app-icon.png\" alt=\"Ticker app icon\" /></div>\n        <div class=\"app-main\">\n          <div class=\"nm\">Ticker <span class=\"cat\">Task &amp; Reminder Manager</span></div>\n          <div class=\"ds\">Comprehensive alarm and reminder app for daily tasks, birthdays, and medication schedules. Customizable alarms, recurring reminders, and smart notifications in an intuitive interface.</div>\n          <div class=\"app-stack\" style=\"margin-top:14px;\"><span>SwiftUI</span><span>Smart Alarms</span><span>Recurring</span><span>Notifications</span></div>\n        </div>\n        <div class=\"app-arrow\">↗</div>\n      </div>\n    </a>\n  </div>\n</section>\n\n<!-- EXPERIENCE -->\n<section class=\"sec\" id=\"experience\">\n  <div class=\"wrap\">\n    <div class=\"sec-num\" data-reveal>04 / EXPERIENCE</div>\n    <div class=\"sec-title\" data-reveal>The ledger.</div>\n    <div class=\"led\">\n\n      <div class=\"led-item\" data-reveal>\n        <div class=\"led-when mono\"><span class=\"yr\">'23—'25</span> Feb 2023 — Jul 2025 <span class=\"loc\">Hyderabad, IN</span></div>\n        <div>\n          <div class=\"led-co\"><h3>Radius</h3><span class=\"role\">Senior iOS Engineer</span></div>\n          <div class=\"led-metrics\"><span>40% faster dev time</span><span>2M+ listings</span></div>\n          <p class=\"led-desc\">Architected a multi-app ecosystem with Tuist across three applications, building a shared design system and networking layer that reduced development time by 40%.</p>\n          <div class=\"led-skills mono\"><span>Tuist</span><span>DocuSign API</span><span>MapKit</span><span>Performance</span><span>Mentorship</span></div>\n        </div>\n      </div>\n\n      <div class=\"led-item\" data-reveal>\n        <div class=\"led-when mono\"><span class=\"yr\">'22—'23</span> Jul 2022 — Jan 2023 <span class=\"loc\">Hyderabad, IN</span></div>\n        <div>\n          <div class=\"led-co\"><h3>Compass</h3><span class=\"role\">iOS Engineer II</span></div>\n          <div class=\"led-metrics\"><span>$200K saved</span><span>$100M+ revenue</span></div>\n          <p class=\"led-desc\">Led a Swift modernisation initiative across a 35-engineer iOS team, implementing The Composable Architecture (TCA) to standardise state management and accelerate delivery.</p>\n          <div class=\"led-skills mono\"><span>TCA</span><span>Core ML</span><span>Swift</span><span>Architecture</span></div>\n        </div>\n      </div>\n\n      <div class=\"led-item\" data-reveal>\n        <div class=\"led-when mono\"><span class=\"yr\">'20—'22</span> Jan 2020 — Jul 2022 <span class=\"loc\">Hyderabad, IN</span></div>\n        <div>\n          <div class=\"led-co\"><h3>Grab</h3><span class=\"role\">iOS Engineer</span></div>\n          <div class=\"led-metrics\"><span>10M+ users reached</span></div>\n          <p class=\"led-desc\">Architected and delivered risk-management features reaching more than 10 million users, working within a large-scale RIBs codebase and contributing to engineering documentation.</p>\n          <div class=\"led-skills mono\"><span>RIBs</span><span>Risk Management</span><span>Scale</span><span>Documentation</span></div>\n        </div>\n      </div>\n\n    </div>\n  </div>\n</section>\n\n<!-- STACK -->\n<section class=\"sec\" id=\"stack\" style=\"padding-bottom:0;\">\n  <div class=\"wrap\">\n    <div class=\"sec-num\" data-reveal>05 / STACK</div>\n    <div class=\"sec-title\" data-reveal>The toolkit.</div>\n  </div>\n  <div class=\"skills-mq\" aria-hidden=\"true\">\n    <div class=\"mq-track\">\n      <span>SWIFT</span><span>SWIFTUI</span><span>COMBINE</span><span>TCA</span><span>RIBS</span><span>TUIST</span><span>CORE DATA</span><span>SWIFTDATA</span><span>CORE ML</span><span>WIDGETKIT</span><span>MAPKIT</span>\n      <span>SWIFT</span><span>SWIFTUI</span><span>COMBINE</span><span>TCA</span><span>RIBS</span><span>TUIST</span><span>CORE DATA</span><span>SWIFTDATA</span><span>CORE ML</span><span>WIDGETKIT</span><span>MAPKIT</span>\n    </div>\n    <div class=\"mq-track rev row2\">\n      <span>UIKIT</span><span>DESIGN SYSTEMS</span><span>PERFORMANCE</span><span>MODULARIZATION</span><span>PUSH NOTIFICATIONS</span><span>MENTORSHIP</span>\n      <span>UIKIT</span><span>DESIGN SYSTEMS</span><span>PERFORMANCE</span><span>MODULARIZATION</span><span>PUSH NOTIFICATIONS</span><span>MENTORSHIP</span>\n    </div>\n  </div>\n  <div class=\"wrap\" style=\"padding-top:46px;padding-bottom:clamp(72px,9vw,128px);\">\n    <div class=\"skills-cols\">\n      <div class=\"skill-col\" data-reveal><h4>Languages &amp; UI</h4><ul><li>Swift</li><li>SwiftUI</li><li>UIKit</li><li>Combine</li></ul></div>\n      <div class=\"skill-col\" data-reveal style=\"--d:.07s\"><h4>Architecture</h4><ul><li>Composable (TCA)</li><li>RIBs</li><li>Tuist Modules</li><li>Design Systems</li></ul></div>\n      <div class=\"skill-col\" data-reveal style=\"--d:.14s\"><h4>Data &amp; ML</h4><ul><li>Core Data</li><li>SwiftData</li><li>Core ML</li><li>Reactive Binding</li></ul></div>\n      <div class=\"skill-col\" data-reveal style=\"--d:.21s\"><h4>Platform</h4><ul><li>WidgetKit</li><li>MapKit</li><li>Push Notifications</li><li>Performance Tuning</li></ul></div>\n    </div>\n  </div>\n</section>\n\n<!-- CONTACT -->\n<section class=\"contact\" id=\"contact\">\n  <div class=\"wrap\" style=\"padding-top:clamp(76px,10vw,130px);padding-bottom:clamp(76px,10vw,130px);\">\n    <div class=\"sec-num\" data-reveal>06 / CONTACT</div>\n    <h2 data-reveal style=\"--d:.04s\">Let's build<br/>something <span class=\"acc\">real.</span></h2>\n    <a class=\"mail\" href=\"mailto:mayankgandhi50@gmail.com\" data-reveal style=\"--d:.1s\">mayankgandhi50@gmail.com <span class=\"acc\">↗</span></a>\n    <div class=\"socials mono\" data-reveal style=\"--d:.16s\">\n      <a href=\"https://github.com/mayankgandhi\" target=\"_blank\" rel=\"noopener noreferrer\">GITHUB <span class=\"ar\">↗</span></a>\n      <a href=\"https://www.linkedin.com/in/mayankgandhi98/\" target=\"_blank\" rel=\"noopener noreferrer\">LINKEDIN <span class=\"ar\">↗</span></a>\n      <a href=\"https://instagram.com/_mayankgandhi\" target=\"_blank\" rel=\"noopener noreferrer\">INSTAGRAM <span class=\"ar\">↗</span></a>\n    </div>\n  </div>\n</section>\n\n<!-- FOOTER -->\n<footer>\n  <div class=\"wrap\">\n    <div>© 2026 MAYANK GANDHI</div>\n    <div class=\"col\">HYDERABAD, IN · UTC+5:30</div>\n    <div class=\"col\">SET IN BRICOLAGE GROTESQUE &amp; JETBRAINS MONO</div>\n    <div><a href=\"#top\">↑ TOP</a></div>\n  </div>\n</footer>";
